export type ItemType = "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface Customer {
  yearsWithMHPCO: number;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface DamageEntry {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: DamageEntry[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioOutput {
  results: StepResult[];
}

interface MainItemSpec {
  insuranceValue: number;
  basePremium: number;
}

const MAIN_ITEM_SPECS: Record<string, MainItemSpec> = {
  sword: { insuranceValue: 1000, basePremium: 100 },
  amulet: { insuranceValue: 600, basePremium: 60 },
  staff: { insuranceValue: 800, basePremium: 80 },
  potion: { insuranceValue: 400, basePremium: 40 },
};

const COMPONENT_TYPES = new Set<string>(["rune", "moonstone"]);
const COMPONENT_VALUE = 250;
const COMPONENT_PREMIUM = 25;
const BLOCK_PREMIUM = 60;
const DEDUCTIBLE = 100;
const PROCESSING_FEE = 5;

function isKnownType(t: string): boolean {
  return t in MAIN_ITEM_SPECS || COMPONENT_TYPES.has(t);
}

function itemInsuranceValue(item: Item): number {
  if (item.type in MAIN_ITEM_SPECS) return MAIN_ITEM_SPECS[item.type].insuranceValue;
  if (COMPONENT_TYPES.has(item.type)) return COMPONENT_VALUE;
  throw new Error(`Unknown item type: ${item.type}`);
}

function itemBasePremium(item: Item): number {
  if (item.type in MAIN_ITEM_SPECS) return MAIN_ITEM_SPECS[item.type].basePremium;
  if (COMPONENT_TYPES.has(item.type)) return COMPONENT_PREMIUM;
  throw new Error(`Unknown item type: ${item.type}`);
}

interface PolicyRecord {
  items: Item[];
  insuranceSum: number;
  cap: number;
  remainingCap: number;
}

/**
 * Compute the base premium for the collection of items, applying the
 * "block of 3 alike components" rule. Returns the policy base premium
 * (sum of item base premiums, with block adjustment for components).
 */
function computeItemBasePremiums(items: Item[]): { perItem: Map<Item, number>; policyBase: number } {
  const perItem = new Map<Item, number>();
  let policyBase = 0;

  // For main items, base premium is just the per-item amount.
  // For components, group by type; every group of 3 same-type components
  // contributes BLOCK_PREMIUM (60 G) instead of 3 × COMPONENT_PREMIUM (75 G).
  // We need to track per-item premium for item-specific modifiers (cursed,
  // high enchantment). Components don't have enchantment levels per the
  // spec examples, but we still need a per-item value for surcharges.
  // For block components, we split the 60 G evenly: 20 G each. This keeps
  // per-item bookkeeping consistent should a future modifier apply.

  const componentGroups = new Map<string, Item[]>();
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
    if (COMPONENT_TYPES.has(item.type)) {
      const list = componentGroups.get(item.type) ?? [];
      list.push(item);
      componentGroups.set(item.type, list);
    } else {
      const base = itemBasePremium(item);
      perItem.set(item, base);
      policyBase += base;
    }
  }

  for (const [, group] of componentGroups) {
    const n = group.length;
    const blocks = Math.floor(n / 3);
    const leftovers = n - blocks * 3;
    const groupTotal = blocks * BLOCK_PREMIUM + leftovers * COMPONENT_PREMIUM;
    policyBase += groupTotal;
    // Distribute group total proportionally per item — even split.
    const perItemAmount = groupTotal / n;
    for (const it of group) {
      perItem.set(it, perItemAmount);
    }
  }

  return { perItem, policyBase };
}

function isCursed(item: Item): boolean {
  return item.cursed === true;
}

function isHighlyEnchanted(item: Item): boolean {
  return (item.enchantment ?? 0) >= 5;
}

function computeQuotePremium(
  items: Item[],
  customer: Customer,
  isFollowUpContract: boolean,
): number {
  // Validate types first
  for (const item of items) {
    if (!isKnownType(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }

  const { perItem, policyBase } = computeItemBasePremiums(items);

  // Item-specific surcharges: cursed (+50% of item base), high enchantment (+30% of item base).
  let itemSurcharges = 0;
  for (const item of items) {
    const base = perItem.get(item) ?? 0;
    if (isCursed(item)) itemSurcharges += base * 0.5;
    if (isHighlyEnchanted(item)) itemSurcharges += base * 0.3;
  }

  let total = policyBase + itemSurcharges;

  // Policy-wide modifiers applied to policy base premium (not surcharged total).
  // Loyalty: -20% of policy base
  if (customer.yearsWithMHPCO >= 2) {
    total -= policyBase * 0.2;
  }
  // First insurance surcharge: +10% of policy base (each item in a quote
  // is treated as a first insurance — applied per-policy-base per spec).
  // The spec example: "100 G base + ... + 10 G first insurance" for a single
  // sword. So 10% of policy base.
  total += policyBase * 0.1;

  // Follow-up contract discount: -15% of policy base
  if (isFollowUpContract) {
    total -= policyBase * 0.15;
  }

  // Processing fee
  total += PROCESSING_FEE;

  // Round up (in MHPCO favor — premium is paid TO MHPCO, so up).
  return Math.ceil(total);
}

function computeInsuranceSum(items: Item[]): number {
  let sum = 0;
  for (const item of items) {
    sum += itemInsuranceValue(item);
  }
  return sum;
}

function isDragonMaterial(item: Item | undefined): boolean {
  return item?.material === "dragon";
}

function highEnchantmentClaim(item: Item | undefined): boolean {
  return (item?.enchantment ?? 0) >= 8;
}

/**
 * Match damage entries to insured items. Each damage entry consumes one
 * matching item from the policy. If the policy doesn't contain enough
 * items of the required type, throws.
 */
function matchDamagesToItems(items: Item[], damages: DamageEntry[]): Item[] {
  // Build a working copy grouped by type
  const remaining = new Map<string, Item[]>();
  for (const item of items) {
    const list = remaining.get(item.type) ?? [];
    list.push(item);
    remaining.set(item.type, list);
  }

  const matched: Item[] = [];
  for (const d of damages) {
    const list = remaining.get(d.itemType);
    if (!list || list.length === 0) {
      throw new Error(`Claim references item not part of policy: ${d.itemType}`);
    }
    matched.push(list.shift()!);
  }
  return matched;
}

function processClaim(policy: PolicyRecord, incident: Incident): ClaimResult {
  // Validate damages
  for (const d of incident.damages) {
    if (d.amount < 0) {
      throw new Error(`Negative damage amount: ${d.amount}`);
    }
    if (!isKnownType(d.itemType)) {
      throw new Error(`Unknown damage item type: ${d.itemType}`);
    }
  }

  const matched = matchDamagesToItems(policy.items, incident.damages);

  let totalPayout = 0;
  for (let i = 0; i < incident.damages.length; i++) {
    const d = incident.damages[i];
    const item = matched[i];

    let reimbursement = d.amount;

    if (isDragonMaterial(item)) {
      // Full reimbursement; high-enchantment 50% applies on top if enchantment ≥ 8
      if (highEnchantmentClaim(item)) {
        reimbursement = d.amount * 0.5;
      }
      // else full
    } else if (highEnchantmentClaim(item)) {
      reimbursement = d.amount * 0.5;
    }

    reimbursement -= DEDUCTIBLE;
    if (reimbursement < 0) reimbursement = 0;

    totalPayout += reimbursement;
  }

  // Round down (in MHPCO favor — payout goes from MHPCO, so down)
  let payout = Math.floor(totalPayout);

  // Apply cap
  if (payout > policy.remainingCap) {
    payout = policy.remainingCap;
  }

  policy.remainingCap -= payout;

  return { payout, remainingCap: policy.remainingCap };
}

export function runScenario(scenario: Scenario): ScenarioOutput {
  const results: StepResult[] = [];
  const policies = new Map<number, PolicyRecord>();
  let quoteCount = 0;

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === "quote") {
      // Validate types first
      for (const item of step.items) {
        if (!isKnownType(item.type)) {
          throw new Error(`Unknown item type: ${item.type}`);
        }
      }

      const isFollowUp = quoteCount > 0;
      const premium = computeQuotePremium(step.items, scenario.customer, isFollowUp);

      const insuranceSum = computeInsuranceSum(step.items);
      const cap = insuranceSum * 2;
      policies.set(i, {
        items: step.items,
        insuranceSum,
        cap,
        remainingCap: cap,
      });

      results.push({ premium });
      quoteCount++;
    } else {
      const policy = policies.get(step.policy);
      if (!policy) {
        throw new Error(`No policy at step index ${step.policy}`);
      }
      const claimResult = processClaim(policy, step.incident);
      results.push(claimResult);
    }
  }

  return { results };
}

