  total += policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
  if (isFollowUpContract) {
    total -= policyBase * FOLLOW_UP_DISCOUNT_RATE;
  }
  total += PROCESSING_FEE;

  return Math.ceil(total);
}

