function isDragonMaterial(item: Item): boolean {
  return item.material === "dragon";
}

function triggersClaimHighEnchantment(item: Item): boolean {
  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
